c
// Allocate for ALL possible CPUs
int num_cpus = libbpf_num_possible_cpus();
uint64_t *values = calloc(num_cpus, sizeof(uint64_t));
// Lookup fills all CPU values
bpf_map_lookup_elem(map_fd, &key, values);
// Sum across all CPUs
uint64_t total = 0;
for (int i = 0; i < num_cpus; i++) {
total += values[i];
}
// total = 12,340 + 8,912 + 15,678 + ... = 52,620

c
// Only reads CPU 0's value!
uint64_t value;
bpf_map_lookup_elem(map_fd, &key, &value);
// value = 12,340 (MISSING other CPUs!)
